UPDATE t_voting_subject
SET party_ratio_floor = #{partyRatioFloor},
    version           = version + 1
WHERE subject_id = #{subjectId}
  AND version = #{expectedVersion}

UPDATE t_voting_subject
SET status      = #{newStatus},
    settled_at  = CASE WHEN #{newStatus} = 5 THEN CURRENT_TIMESTAMP ELSE settled_at END,
    version     = version + 1
WHERE subject_id = #{subjectId}
  AND version = #{expectedVersion}

